var surah067 = {
  number: 67,
  nameArabic: "al-Mulk",
  nameEnglish: "Al-Mulk",
  meaning: "The Sovereignty",
  totalAyahs: 30,
  ayahs: [
    { number: 1, arabic: "تَبَٰرَكَ ٱلَّذِى بِيَدِهِ ٱلْمُلْكُ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Tabaraka allathee biyadihi almulku wahuwa AAala kulli shayin qadeerun", transliterationB: "Tabaarakal lazee biyadihil mulku wa huwa 'alaa kulli shai-in qadeer", english: "Blessed be He in Whose hands is Dominion; and He over all things hath Power", romanUrdu: "Nihayat buzurg-o-bartar hai woh jiske haath mein qayinaat ki sultanat hai , aur woh har cheez par qudrat rakhta hai" },
    { number: 2, arabic: "ٱلَّذِى خَلَقَ ٱلْمَوْتَ وَٱلْحَيَوٰةَ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًۭا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْغَفُورُ", transliteration: "Allathee khalaqa almawta waalhayata liyabluwakum ayyukum ahsanu AAamalan wahuwa alAAazeezu alghafooru", transliterationB: "Allazee khalaqal mawta walhayaata liyabluwakum ayyukum ahsanu 'amalaa; wa huwal 'azeezul ghafoor", english: "He Who created Death and Life, that He may try which of you is best in deed: and He is the Exalted in Might, Oft-Forgiving", romanUrdu: "Jisne maut aur zindagi ko ijaat kiya taa-ke tum logon ko aazma kar dekhey tum mein se kaun behtar amal karne wala hai, aur woh zabardast bhi hai aur darguzar farmane wala bhi" },
    { number: 3, arabic: "ٱلَّذِى خَلَقَ سَبْعَ سَمَٰوَٰتٍۢ طِبَاقًۭا ۖ مَّا تَرَىٰ فِى خَلْقِ ٱلرَّحْمَٰنِ مِن تَفَٰوُتٍۢ ۖ فَٱرْجِعِ ٱلْبَصَرَ هَلْ تَرَىٰ مِن فُطُورٍۢ", transliteration: "Allathee khalaqa sabAAa samawatin tibaqan ma tara fee khalqi alrrahmani min tafawutin fairjiAAi albasara hal tara min futoorin", transliterationB: "Allazee khalaqa sab'a samaawaatin tibaaqam maa taraa fee khalqir rahmaani min tafaawutin farji'il basara hal taraa min futoor", english: "He Who created the seven heavens one above another: No want of proportion wilt thou see in the Creation of (Allah) Most Gracious. So turn thy vision again: seest thou any flaw", romanUrdu: "Jisne teh-bar-teh saat (seven) aasman banaye tum Rehman ki takhleeq(creation) mein kisi kism ki be-rabti (incongruity) na paogey phir palat kar dekho, kahin tumhein koi khalal (flaw) nazar aata hai" },
    { number: 4, arabic: "ثُمَّ ٱرْجِعِ ٱلْبَصَرَ كَرَّتَيْنِ يَنقَلِبْ إِلَيْكَ ٱلْبَصَرُ خَاسِئًۭا وَهُوَ حَسِيرٌۭ", transliteration: "Thumma irjiAAi albasara karratayni yanqalib ilayka albasaru khasian wahuwa haseerun", transliterationB: "Summar ji'il basara karrataini yanqalib ilaikal basaru khaasi'anw wa huwa haseer", english: "Again turn thy vision a second time: (thy) vision will come back to thee dull and discomfited, in a state worn out", romanUrdu: "Baar baar nigaah daudao tumhari nigaah thak kar na-murad palat aayegi" },
    { number: 5, arabic: "وَلَقَدْ زَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَٰبِيحَ وَجَعَلْنَٰهَا رُجُومًۭا لِّلشَّيَٰطِينِ ۖ وَأَعْتَدْنَا لَهُمْ عَذَابَ ٱلسَّعِيرِ", transliteration: "Walaqad zayyanna alssamaa alddunya bimasabeeha wajaAAalnaha rujooman lilshshayateeni waaAAtadna lahum AAathaba alssaAAeeri", transliterationB: "Wa laqad zaiyannas samaaa'ad dunyaa bimasaa beeha wa ja'alnaahaa rujoomal lish shayaateeni wa a'tadnaa lahum 'azaabas sa'eer", english: "And we have, (from of old), adorned the lowest heaven with Lamps, and We have made such (Lamps) (as) missiles to drive away the Evil Ones, and have prepared for them the Penalty of the Blazing Fire", romanUrdu: "Humne tumhare kareeb ke aasman ko azeem-o-shaan chiragon se aarasta (adorned /beautify) kiya hai aur unhein shayateen ko maar bhagane ka zariya bana diya hai. In shaytano ke liye bhadakti hui aag humne muhayya kar rakkhi hai" },
    { number: 6, arabic: "وَلِلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ عَذَابُ جَهَنَّمَ ۖ وَبِئْسَ ٱلْمَصِيرُ", transliteration: "Walillatheena kafaroo birabbihim AAathabu jahannama wabisa almaseeru", transliterationB: "Wa lillazeena kafaroo bi rabbihim 'azaabu jahannama wa bi'sal maseer", english: "For those who reject their Lord (and Cherisher) is the Penalty of Hell: and evil is (such), Destination", romanUrdu: "Jin logon ne apne Rubb se kufr kiya hai unke liye jahannum ka azaab hai aur woh bahut hi bura thikana hai" },
    { number: 7, arabic: "إِذَآ أُلْقُوا۟ فِيهَا سَمِعُوا۟ لَهَا شَهِيقًۭا وَهِىَ تَفُورُ", transliteration: "Itha olqoo feeha samiAAoo laha shaheeqan wahiya tafooru", transliterationB: "Izaaa ulqoo feehaa sami'oo lahaa shaheeqanw wa hiya tafoor", english: "When they are cast therein, they will hear the (terrible) drawing in of its breath even as it blazes forth", romanUrdu: "Jab woh usmein phenke jayenge to uske dhahadne (roar) ki haulnaak aawaz sunengey aur woh josh kha rahi hogi" },
    { number: 8, arabic: "تَكَادُ تَمَيَّزُ مِنَ ٱلْغَيْظِ ۖ كُلَّمَآ أُلْقِىَ فِيهَا فَوْجٌۭ سَأَلَهُمْ خَزَنَتُهَآ أَلَمْ يَأْتِكُمْ نَذِيرٌۭ", transliteration: "Takadu tamayyazu mina alghaythi kullama olqiya feeha fawjun saalahum khazanatuha alam yatikum natheerun", transliterationB: "Takaadu tamayyazu minal ghaizi kullamaaa uliqya feehaa fawjun sa alahum khazanatuhaaa alam yaatikum nazeer", english: "Almost bursting with fury: Every time a Group is cast therein, its Keepers will ask, \"Did no Warner come to you", romanUrdu: "Shiddat-e-gazab se phati jati hogi, har baar jab koi anbwah (multitude/group) us mein dala jayega uske kaarinde (keepers) un logon se puchenge “kya tumhare paas koi khabardaar karne wala nahin aaya tha?”" },
    { number: 9, arabic: "قَالُوا۟ بَلَىٰ قَدْ جَآءَنَا نَذِيرٌۭ فَكَذَّبْنَا وَقُلْنَا مَا نَزَّلَ ٱللَّهُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا فِى ضَلَٰلٍۢ كَبِيرٍۢ", transliteration: "Qaloo bala qad jaana natheerun fakaththabna waqulna ma nazzala Allahu min shayin in antum illa fee dalalin kabeerin", transliterationB: "Qaaloo balaa qad jaaa'anaa nazeerun fakazzabnaa wa qulnaa maa nazzalal laahu min shai in in antum illaa fee dalaalin kabeer", english: "They will say: \"Yes indeed; a Warner did come to us, but we rejected him and said, 'Allah never sent down any (Message): ye are nothing but an egregious delusion", romanUrdu: "Woh jawab denge “haan ,khabardaar karne wala hamare paas aaya tha,magar humne usey jhutla diya aur kaha Allah ne kuch bhi nazil nahin kiya hai, tum badi gumraahi mein padey huey ho”" },
    { number: 10, arabic: "وَقَالُوا۟ لَوْ كُنَّا نَسْمَعُ أَوْ نَعْقِلُ مَا كُنَّا فِىٓ أَصْحَٰبِ ٱلسَّعِيرِ", transliteration: "Waqaloo law kunna nasmaAAu aw naAAqilu ma kunna fee ashabi alssaAAeeri", transliterationB: "Wa qaaloo law kunnaa nasma'u awna'qilu maa kunnaa feee as haabis sa'eer", english: "They will further say: \"Had we but listened or used our intelligence, we should not (now) be among the Companions of the Blazing Fire", romanUrdu: "Aur woh kahenge “kaash hum sunte ya samajhte to aaj is bhadakti hui aag ke sazawaron mein na shamil hotey”" },
    { number: 11, arabic: "فَٱعْتَرَفُوا۟ بِذَنۢبِهِمْ فَسُحْقًۭا لِّأَصْحَٰبِ ٱلسَّعِيرِ", transliteration: "FaiAAtarafoo bithanbihim fasuhqan liashabi alssaAAeeri", transliterationB: "Fa'tarafoo bizambihim fasuhqal li as haabis sa'eer", english: "They will then confess their sins: but far will be (Forgiveness) from the Companions of the Blazing Fire", romanUrdu: "Is tarah woh apne kasoor ka khud aitraaf (confess) kar lengey, laanat hai in dozakhiyon par" },
    { number: 12, arabic: "إِنَّ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ لَهُم مَّغْفِرَةٌۭ وَأَجْرٌۭ كَبِيرٌۭ", transliteration: "Inna allatheena yakhshawna rabbahum bialghaybi lahum maghfiratun waajrun kabeerun", transliterationB: "Innal lazeena yakhshawna rabbahum bilghaibi lahum maghfiratunw wa ajrun kabeer", english: "As for those who fear their Lord unseen, for them is Forgiveness and a great Reward", romanUrdu: "Jo log be-dekhe apne Rubb se darte hai , yaqeenan unke liye magfirat hai aur bada ajar" },
    { number: 13, arabic: "وَأَسِرُّوا۟ قَوْلَكُمْ أَوِ ٱجْهَرُوا۟ بِهِۦٓ ۖ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Waasirroo qawlakum awi ijharoo bihi innahu AAaleemun bithati alssudoori", transliterationB: "Wa asirroo qawlakum awijharoo bihee innahoo 'aleemum bizaatis sudoor", english: "And whether ye hide your word or publish it, He certainly has (full) knowledge, of the secrets of (all) hearts", romanUrdu: "Tum khwah chupke se baat karo ya unchi aawaz se (Allah ke liye yaksa hai) woh to dilon ka haal tak jaanta hai" },
    { number: 14, arabic: "أَلَا يَعْلَمُ مَنْ خَلَقَ وَهُوَ ٱللَّطِيفُ ٱلْخَبِيرُ", transliteration: "Ala yaAAlamu man khalaqa wahuwa allateefu alkhabeeru", transliterationB: "Alaa ya'lamu man khalaq wa huwal lateeful khabeer", english: "Should He not know,- He that created? and He is the One that understands the finest mysteries (and) is well-acquainted (with them)", romanUrdu: "Kya wahi na jaanega jisne paida kiya hai? Halanke woh baareek-been aur bakhabar hai" },
    { number: 15, arabic: "هُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ ذَلُولًۭا فَٱمْشُوا۟ فِى مَنَاكِبِهَا وَكُلُوا۟ مِن رِّزْقِهِۦ ۖ وَإِلَيْهِ ٱلنُّشُورُ", transliteration: "Huwa allathee jaAAala lakumu alarda thaloolan faimshoo fee manakibiha wakuloo min rizqihi wailayhi alnnushooru", transliterationB: "Huwal lazee ja'ala lakumul arda zaloolan famshoo fee manaakibihaa wa kuloo mir rizqihee wa ilaihin nushoor", english: "It is He Who has made the earth manageable for you, so traverse ye through its tracts and enjoy of the Sustenance which He furnishes: but unto Him is the Resurrection", romanUrdu: "Wahi to hai jisne tumhare liye zameen ko taabeh kar rakkha hai , chalo uski chaati par aur khao khuda ka rizq, usi ke huzoor tumhein dobara zinda ho kar jana hai" },
    { number: 16, arabic: "ءَأَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يَخْسِفَ بِكُمُ ٱلْأَرْضَ فَإِذَا هِىَ تَمُورُ", transliteration: "Aamintum man fee alssamai an yakhsifa bikumu alarda faitha hiya tamooru", transliterationB: "A-amintum man fissamaaa'i aiyakhsifa bi kumul arda fa izaa hiya tamoor", english: "Do ye feel secure that He Who is in heaven will not cause you to be swallowed up by the earth when it shakes (as in an earthquake)", romanUrdu: "Kya tum issey be-khauf ho ke woh jo aasman mein hai tumhein zameen mein dhasa de aur yakayak yeh zameen jhakoley khane lagey (shake/rock violently)" },
    { number: 17, arabic: "أَمْ أَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يُرْسِلَ عَلَيْكُمْ حَاصِبًۭا ۖ فَسَتَعْلَمُونَ كَيْفَ نَذِيرِ", transliteration: "Am amintum man fee alssamai an yursila AAalaykum hasiban fasataAAlamoona kayfa natheeri", transliterationB: "Am amintum man fissamaaa'i ai yursila 'alaikum haasiban fasata'lamoona kaifa nazeer", english: "Or do ye feel secure that He Who is in Heaven will not send against you a violent tornado (with showers of stones), so that ye shall know how (terrible) was My warning", romanUrdu: "Kya tum issey be-khauf ho ke wo jo aasman mein hai tum par pathrao karne wali hawa bhej de? Phir tumhein maloom ho jayega ke meri tambeeh (warning) kaisi hoti hai" },
    { number: 18, arabic: "وَلَقَدْ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ فَكَيْفَ كَانَ نَكِيرِ", transliteration: "Walaqad kaththaba allatheena min qablihim fakayfa kana nakeeri", transliterationB: "Wa laqad kazzabal lazeena min qablihim fakaifa kaana nakeer", english: "But indeed men before them rejected (My warning): then how (terrible) was My rejection (of them)", romanUrdu: "Inse pehle guzre huey log jhutla chuke hain phir dekhlo ke meri giraft kaisi sakht thi" },
    { number: 19, arabic: "أَوَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ فَوْقَهُمْ صَٰٓفَّٰتٍۢ وَيَقْبِضْنَ ۚ مَا يُمْسِكُهُنَّ إِلَّا ٱلرَّحْمَٰنُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍۭ بَصِيرٌ", transliteration: "Awalam yaraw ila alttayri fawqahum saffatin wayaqbidna ma yumsikuhunna illa alrrahmanu innahu bikulli shayin baseerun", transliterationB: "Awalam yaraw ilat tairi fawqahum saaaffaatinw wa yaqbidn; maa yumsikuhunna illaar rahmaan; innahoo bikulli shai im baseer", english: "Do they not observe the birds above them, spreading their wings and folding them in? None can uphold them except (Allah) Most Gracious: Truly (Allah) Most Gracious: Truly it is He that watches over all things", romanUrdu: "Kya yeh log apne upar udney waley parindon ko par phaylaye aur sukedte nahin dekhte? Rehman ke siwa koi nahin jo inhein thamey huey ho. Wahi har cheez ka nigehbaan hai" },
    { number: 20, arabic: "أَمَّنْ هَٰذَا ٱلَّذِى هُوَ جُندٌۭ لَّكُمْ يَنصُرُكُم مِّن دُونِ ٱلرَّحْمَٰنِ ۚ إِنِ ٱلْكَٰفِرُونَ إِلَّا فِى غُرُورٍ", transliteration: "Amman hatha allathee huwa jundun lakum yansurukum min dooni alrrahmani ini alkafiroona illa fee ghuroorin", transliterationB: "Amman haazal lazee huwa jundul lakum yansurukum min doonir rahmaan; inilkaafiroona illaa fee ghuroor", english: "Nay, who is there that can help you, (even as) an army, besides (Allah) Most Merciful? In nothing but delusion are the Unbelievers", romanUrdu: "Batao, aakhir woh kaunsa lashkar tumhare paas hai jo Rehman ke muqable mein tumhari madad kar sakta hai? Haqeeqat yeh hai ke yeh mukireen dhoke mein padey huey hain" },
    { number: 21, arabic: "أَمَّنْ هَٰذَا ٱلَّذِى يَرْزُقُكُمْ إِنْ أَمْسَكَ رِزْقَهُۥ ۚ بَل لَّجُّوا۟ فِى عُتُوٍّۢ وَنُفُورٍ", transliteration: "Amman hatha allathee yarzuqukum in amsaka rizqahu bal lajjoo fee AAutuwwin wanufoorin", transliterationB: "Amman haazal lazee yarzuqukum in amsaka rizqah; bal lajjoo fee 'utuwwinw wa nufoor", english: "Or who is there that can provide you with Sustenance if He were to withhold His provision? Nay, they obstinately persist in insolent impiety and flight (from the Truth)", romanUrdu: "Ya phir batao, kaun hai jo tumhein rizq de sakta hai agar Rehman apna rizq roak ley? Dar-asal yeh log sarkashi aur haqq se gurez par adey huey hai" },
    { number: 22, arabic: "أَفَمَن يَمْشِى مُكِبًّا عَلَىٰ وَجْهِهِۦٓ أَهْدَىٰٓ أَمَّن يَمْشِى سَوِيًّا عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Afaman yamshee mukibban AAala wajhihi ahda amman yamshee sawiyyan AAala siratin mustaqeemin", transliterationB: "Afamai yamshee mukibban 'alaa wajhihee ahdaaa ammany yamshee sawiyyan 'alaa siratim mustaqeem", english: "Is then one who walks headlong, with his face grovelling, better guided,- or one who walks evenly on a Straight Way", romanUrdu: "Bhala socho, jo shaks mooh aundhaey (grovelling) chal raha ho woh zyada sahih raah paney wala hai ya woh jo sar uthaye seedha ek hamwar sadak par chal raha ho" },
    { number: 23, arabic: "قُلْ هُوَ ٱلَّذِىٓ أَنشَأَكُمْ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۖ قَلِيلًۭا مَّا تَشْكُرُونَ", transliteration: "Qul huwa allathee anshaakum wajaAAala lakumu alssamAAa waalabsara waalafidata qaleelan ma tashkuroona", transliterationB: "Qul huwal lazee ansha akum wa ja'ala lakumus sam'a wal absaara wal af'idata qaleelam maa tashkuroon", english: "Say: \"It is He Who has created you (and made you grow), and made for you the faculties of hearing, seeing, feeling and understanding: little thanks it is ye give", romanUrdu: "Inse kaho Allah hi hai jisne tumhein paida kiya, tumko sunney aur dekhne ki taaqatein di aur sochne samajhne waley dil diye, magar tum kam hi shukr ada karte ho" },
    { number: 24, arabic: "قُلْ هُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ", transliteration: "Qul huwa allathee tharaakum fee alardi wailayhi tuhsharoona", transliterationB: "Qul huwal lazee zara akum fil ardi wa ilaihi tuhsharoon", english: "Say: \"It is He Who has multiplied you through the earth, and to Him shall ye be gathered together", romanUrdu: "Insey kaho, Allah hi hai jisne tumhein zameen mein phailaya hai aur usi ki taraf tum sametey jaogey" },
    { number: 25, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alwaAAdu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal wa'du in kuntum saadiqeen", english: "They ask: When will this promise be (fulfilled)? - If ye are telling the truth", romanUrdu: "Yeh kehte hain “Agar tum sacchey ho to batao yeh wada kab poora hoga?”" },
    { number: 26, arabic: "قُلْ إِنَّمَا ٱلْعِلْمُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌۭ", transliteration: "Qul innama alAAilmu AAinda Allahi wainnama ana natheerun mubeenun", transliterationB: "Qul innamal 'ilmu 'indallaahi wa innamaaa ana nazeerum mubeen", english: "Say: \"As to the knowledge of the time, it is with Allah alone: I am (sent) only to warn plainly in public", romanUrdu: "Kaho “Iska ilm to Allah ke paas hai, main to bas saaf saaf khabardar kardene wala hoon" },
    { number: 27, arabic: "فَلَمَّا رَأَوْهُ زُلْفَةًۭ سِيٓـَٔتْ وُجُوهُ ٱلَّذِينَ كَفَرُوا۟ وَقِيلَ هَٰذَا ٱلَّذِى كُنتُم بِهِۦ تَدَّعُونَ", transliteration: "Falamma raawhu zulfatan seeat wujoohu allatheena kafaroo waqeela hatha allathee kuntum bihi taddaAAoona", transliterationB: "Falaammaa ra-awhu zulfatan seee'at wujoohul lazeena kafaroo wa qeela haazal lazee kuntum bihee tadda'oon", english: "At length, when they see it close at hand, grieved will be the faces of the Unbelievers, and it will be said (to them): \"This is (the promise fulfilled), which ye were calling for", romanUrdu: "Phir jab yeh us cheez ko kareeb dekh lenge to un sab logon ke chehre bigad jayenge jinhon ne inkar kiya hai, aur us waqt unse kaha jayega ke yahi hai woh cheez jiske liye tum takazey kar rahey (ask for) thay" },
    { number: 28, arabic: "قُلْ أَرَءَيْتُمْ إِنْ أَهْلَكَنِىَ ٱللَّهُ وَمَن مَّعِىَ أَوْ رَحِمَنَا فَمَن يُجِيرُ ٱلْكَٰفِرِينَ مِنْ عَذَابٍ أَلِيمٍۢ", transliteration: "Qul araaytum in ahlakaniya Allahu waman maAAiya aw rahimana faman yujeeru alkafireena min AAathabin aleemin", transliterationB: "Qul ara'aytum in ahlaka niyal laahu wa mam ma'iya aw rahimanaa famai-yujeerul kaafireena min 'azaabin aleem", english: "Say: \"See ye?- If Allah were to destroy me, and those with me, or if He bestows His Mercy on us,- yet who can deliver the Unbelievers from a grievous Penalty", romanUrdu: "Insey kaho, kabhi tumne yeh bhi socha ke Allah khwa mujhey aur mere saathiyon ko halaaq karde ya hum par Reham karey, kafiron ko dardnaak azaab se kaun bacha lega" },
    { number: 29, arabic: "قُلْ هُوَ ٱلرَّحْمَٰنُ ءَامَنَّا بِهِۦ وَعَلَيْهِ تَوَكَّلْنَا ۖ فَسَتَعْلَمُونَ مَنْ هُوَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Qul huwa alrrahmanu amanna bihi waAAalayhi tawakkalna fasataAAlamoona man huwa fee dalalin mubeenin", transliterationB: "Qul huwar rahmaanu aamannaa bihee wa 'alaihi tawakkalnaa fasata'lamoona man huwa fee dalaalim mubeen", english: "Say: \"He is (Allah) Most Gracious: We have believed in Him, and on Him have we put our trust: So, soon will ye know which (of us) it is that is in manifest error", romanUrdu: "Insey kaho, woh bada Raheem hai, usi par hum imaan laye hain, aur usi par hamara bharosa hai, ankareeb tumhein maloom ho jayega ke sareeh gumrahi (manifest error) mein pada hua kaun hai" },
    { number: 30, arabic: "قُلْ أَرَءَيْتُمْ إِنْ أَصْبَحَ مَآؤُكُمْ غَوْرًۭا فَمَن يَأْتِيكُم بِمَآءٍۢ مَّعِينٍۭ", transliteration: "Qul araaytum in asbaha maokum ghawran faman yateekum bimain maAAeenin", transliterationB: "Qul ara'aytum in asbaha maaa'ukum ghawran famai yaateekum bimaaa'im ma'een", english: "Say: \"See ye?- If your stream be some morning lost (in the underground earth), who then can supply you with clear-flowing water", romanUrdu: "Inse kaho, kabhi tumne yeh bhi socha ke agar tumhare kuwon (wells) ka pani zameen mein utar jaye to kaun hai jo is pani ki behti hui sotein (flowing water) tumhein nikal kar la dega" }
  ]
};
